SELECT sp.id, sp.author_id AS authorId, u.nickname AS authorName, u.avatar AS authorAvatar, sp.content, sp.images, sp.images_count AS imagesCount, sp.comments_count AS commentsCount, sp.likes_count AS likesCount, EXISTS( SELECT 1 FROM space_like sl WHERE sl.post_id = sp.id AND sl.user_id = #{currentUserId} ) AS liked, sp.created_time AS createdTime FROM space_post sp LEFT JOIN user u ON sp.author_id = u.id WHERE sp.id IN
#{id}
AND sp.status = 0 ORDER BY FIELD(sp.id,
#{id}
)
